   232	// @Success 200 {object} models.TaskBucket "The updated task bucket."
   233	// @Failure 400 {object} web.HTTPError "Invalid task bucket object provided."
   234	// @Failure 500 {object} models.Message "Internal error"
   235	// @Router /projects/{project}/views/{view}/buckets/{bucket}/tasks [post]
   236	func (b *TaskBucket) Update(s *xorm.Session, a web.Auth) (err error) {
   237		err = updateTaskBucket(s, a, b)
   238		if err != nil {
   239			return err
   240		}
   241	
   242		if b.Task != nil {
   243			doer, _ := user.GetFromAuth(a)
   244			events.DispatchOnCommit(s, &TaskUpdatedEvent{
   245				Task: b.Task,
   246				Doer: doer,
   247			})
   248		}
   249		return nil
   250	}

