	unreadStatuses := []*TaskUnreadStatus{}
	err = s.In("task_id", taskIDs).
		Where("user_id = ?", a.GetID()).
		Find(&unreadStatuses)
	if err != nil {
		return err
	}

	b := true
	for _, status := range unreadStatuses {
		if task, exists := taskMap[status.TaskID]; exists {
			task.IsUnread = &b
		}
	}

	return nil
}

