	return config.ServicePublicURL.GetString() + "tasks/" + strconv.FormatInt(t.ID, 10)
}

func (t *Task) isRepeating() bool {
	return t.RepeatAfter > 0 ||
		t.RepeatMode == TaskRepeatModeMonth
}

